import React, { useEffect, useRef, useState } from "react";
import "./EeshaWalkComponent.css";

// ── Constants (identical to index.html) ──────────────────────────────────────
const SENSITIVITY      = 1.8;
const STEP_LEAD        = 1.10;
const FREEZE_THRESHOLD = 2500;   // ms
const FAST_WIN_SIZE    = 5;
const SLOW_WIN_SIZE    = 30;
const MIN_STEP_MS      = 350;

export default function EeshaWalkComponent({ audioCtx, soundType, onStop }) {
  const [bpm,      setBpm]      = useState("--");
  const [isFrozen, setIsFrozen] = useState(false);
  const [steps,    setSteps]    = useState(0);

  // All mutable state lives in a ref so closures always see fresh values
  const st = useRef({
    lastStepTime: 0,
    currentBPM:   80,
    fastWin:      [],
    slowWin:      [],
    side:         0,
    isRunning:    false,   // set true on mount, false on cleanup
  });

  // Keep the exact event-listener reference so removeEventListener works
  const motionRef = useRef(null);

  useEffect(() => {
    const s = st.current;
    s.isRunning = true;   // reset every mount (handles React strict-mode double-run)

    const init = async () => {
      if (typeof DeviceMotionEvent?.requestPermission === "function") {
        const res = await DeviceMotionEvent.requestPermission();
        if (res !== "granted") { onStop(); return; }
      }
      motionRef.current = handleMotion;
      window.addEventListener("devicemotion", motionRef.current);
      scheduleNextBeat();
    };

    init();

    return () => {
      s.isRunning = false;
      if (motionRef.current) {
        window.removeEventListener("devicemotion", motionRef.current);
        motionRef.current = null;
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // ── Step detection — exact logic from index.html ──────────────────────────
  function handleMotion(e) {
    const acc = e.acceleration;
    if (!acc) return;

    const mag = Math.sqrt((acc.x ?? 0) ** 2 + (acc.y ?? 0) ** 2 + (acc.z ?? 0) ** 2);
    const s   = st.current;

    s.fastWin.push(mag); if (s.fastWin.length > FAST_WIN_SIZE) s.fastWin.shift();
    s.slowWin.push(mag); if (s.slowWin.length > SLOW_WIN_SIZE) s.slowWin.shift();
    if (s.slowWin.length < SLOW_WIN_SIZE) return;

    const fastAvg = s.fastWin.reduce((a, b) => a + b) / FAST_WIN_SIZE;
    const slowAvg = s.slowWin.reduce((a, b) => a + b) / SLOW_WIN_SIZE;
    const ratio   = fastAvg / (slowAvg + 0.001);

    const now = Date.now();
    if (ratio > SENSITIVITY && now - s.lastStepTime > MIN_STEP_MS) {
      if (s.lastStepTime > 0) {
        const interval  = now - s.lastStepTime;
        s.currentBPM    = (60000 / interval) * STEP_LEAD;
        setBpm(Math.round(60000 / interval));
      }
      s.lastStepTime = now;
      setIsFrozen(false);
      setSteps(n => n + 1);
    }
  }

  // ── Metronome — exact logic from index.html ───────────────────────────────
  function scheduleNextBeat() {
    if (!st.current.isRunning) return;

    const s   = st.current;
    const now = Date.now();
    const timeSinceLast = now - s.lastStepTime;
    let nextInterval;

    if (s.lastStepTime > 0 && timeSinceLast > FREEZE_THRESHOLD) {
      setIsFrozen(true);
      playClick(0, 1400);      // rescue beat — high pitch, centred
      nextInterval = 400;      // fast cadence to prompt restart
    } else {
      playClick(s.side === 0 ? -0.6 : 0.6, soundType === "bell" ? 523 : 800);
      s.side     = 1 - s.side;
      nextInterval = 60000 / Math.min(Math.max(s.currentBPM, 40), 160);
    }

    setTimeout(scheduleNextBeat, nextInterval);
  }

  // ── Audio — exact logic from index.html ──────────────────────────────────
  function playClick(pan, freq) {
    if (!audioCtx) return;
    const now  = audioCtx.currentTime;
    const osc    = audioCtx.createOscillator();
    const panner = audioCtx.createStereoPanner();
    const gain   = audioCtx.createGain();

    osc.type = soundType === "bell" ? "sine"
             : soundType === "bass" ? "sawtooth"
             : "square";

    osc.frequency.setValueAtTime(freq, now);
    panner.pan.setValueAtTime(pan, now);
    gain.gain.setValueAtTime(0.4, now);
    gain.gain.exponentialRampToValueAtTime(0.01, now + 0.12);

    // Separate connects — avoid chaining which is unreliable in some browsers
    osc.connect(panner);
    panner.connect(gain);
    gain.connect(audioCtx.destination);

    osc.start(now);
    osc.stop(now + 0.12);
  }

  // ── UI ────────────────────────────────────────────────────────────────────
  return (
    <div className={`eesha-walk ${isFrozen ? "eesha-frozen" : ""}`}>

      <div className="eesha-status">
        {isFrozen ? "FREEZE DETECTED" : "WALKING"}
      </div>

      <div className="eesha-bpm-display">
        <span className="eesha-bpm-number">{bpm}</span>
        <span className="eesha-bpm-unit">BPM</span>
      </div>

      <div className="eesha-stat-row">
        <div className="eesha-stat">
          <span className="eesha-stat-value">{steps}</span>
          <span className="eesha-stat-label">Steps</span>
        </div>
        <div className="eesha-stat-divider" />
        <div className="eesha-stat">
          <span className="eesha-stat-value">
            {bpm === "--" ? "--" : Math.round(Number(bpm) * STEP_LEAD)}
          </span>
          <span className="eesha-stat-label">Playing</span>
        </div>
      </div>

      <button className="eesha-stop-btn" onClick={onStop}>
        STOP
      </button>
    </div>
  );
}
